@page "/book-appointment"
@rendermode InteractiveServer
@using sv_008ac399f4124375a45810ab2c74ad0d.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm EditContext="editContext" OnSubmit="HandleSubmit">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ───── STEP 1 ───── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label">
                Patient Name
                <InputText class="form-control" @bind-Value="model.PatientName" />
                <ValidationMessage For="() => model.PatientName" />
            </label>
        </div>

        <div class="mb-3">
            <label class="form-label">
                Email
                <InputText class="form-control" @bind-Value="model.Email" />
                <ValidationMessage For="() => model.Email" />
            </label>
        </div>

        <div class="mb-3">
            <label class="form-label">
                Phone
                <InputText class="form-control" @bind-Value="model.Phone" />
                <ValidationMessage For="() => model.Phone" />
            </label>
        </div>

        <div class="mb-3">
            <label class="form-label">
                Insurance Provider
                <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
                    <option value="">-- Select --</option>
                    <option value="Aetna">Aetna</option>
                    <option value="BlueCross">BlueCross</option>
                    <option value="Cigna">Cigna</option>
                    <option value="UnitedHealth">UnitedHealth</option>
                    <option value="None">None</option>
                </InputSelect>
                <ValidationMessage For="() => model.InsuranceProvider" />
            </label>
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="AdvanceToStep2">
                Next
            </button>
        }
    </fieldset>

    @* ───── STEP 2 ───── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label">
                    Preferred Doctor
                    <InputSelect class="form-select" @bind-Value="model.Doctor"
                                 @bind:after="OnDoctorOrDateChanged">
                        <option value="">-- Select --</option>
                        @foreach (var doc in doctors)
                        {
                            <option value="@doc.Name">@doc.Name</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.Doctor" />
                </label>
            </div>

            <div class="mb-3">
                <label class="form-label">
                    Date
                    <InputDate class="form-control" @bind-Value="model.AppointmentDate"
                               @bind:after="OnDoctorOrDateChanged" />
                    <ValidationMessage For="() => model.AppointmentDate" />
                </label>
            </div>

            <div class="mb-3">
                <label class="form-label">
                    Time Slot
                    <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in availableSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => model.TimeSlot" />
                </label>
            </div>

            <div class="mb-3">
                <label class="form-label">
                    Reason for Visit
                    <InputTextArea class="form-control" @bind-Value="model.Reason" rows="3" />
                    <ValidationMessage For="() => model.Reason" />
                </label>
            </div>

            <button type="submit" class="btn btn-success" disabled="@isSubmitting">
                @(isSubmitting ? "Checking..." : "Check Availability")
            </button>
        </fieldset>
    }
</EditForm>

@if (submitted)
{
    <div class="alert alert-success mt-4" role="alert">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool submitted;

    private List<DoctorInfo> doctors = [];
    private List<string> availableSlots = [];

    // Fields that belong to step 1 only
    private static readonly string[] step1Fields =
        [nameof(AppointmentModel.PatientName), nameof(AppointmentModel.Email),
         nameof(AppointmentModel.Phone), nameof(AppointmentModel.InsuranceProvider)];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void AdvanceToStep2()
    {
        // Validate only step-1 fields
        var isValid = editContext.Validate();
        if (!isValid)
        {
            // Check if all errors are outside step 1 (step-2 fields aren't filled yet)
            var messages = editContext.GetValidationMessages();
            var step1Messages = step1Fields
                .SelectMany(f => editContext.GetValidationMessages(editContext.Field(f)));

            if (step1Messages.Any())
            {
                return;
            }
        }

        showStep2 = true;
    }

    private async Task OnDoctorOrDateChanged()
    {
        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
            model.TimeSlot = null;
        }
    }

    private async Task HandleSubmit()
    {
        submitted = false;
        customValidator?.ClearErrors();

        if (!editContext.Validate())
            return;

        isSubmitting = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                model.Email!, model.InsuranceProvider!, model.Doctor!, model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

